"use strict";parserFactory.register("m.gzbpi.com",()=>new GzbpParser);class GzbpParser extends Parser{constructor(){super()}async getChapterUrls(e,t){let r=e.baseURI.replace("/info/","/wapbook/"),l=(await HttpClient.wrapFetch(r)).responseXML;return await this.walkTocPages(l,this.getChapterUrlsFromTocPage,this.nextTocPageUrl,t)}getChapterUrlsFromTocPage(e){return[...e.querySelectorAll("ul.fk li a")].filter(e=>e.href.includes("wapbook")).map(e=>util.hyperLinkToChapter(e))}nextTocPageUrl(e){let t=e.querySelector("div.xypa a");return null===t?null:t.href}findContent(e){return e.querySelector("div#content-txt")}extractTitleImpl(e){let t=e.querySelector("div.xx li");return null===t?null:t.textContent}removeUnwantedElementsFromContentElement(e){let t=[...e.querySelectorAll("div")].filter(e=>e.textContent.includes("本章未完，点击下一篇继续阅读！"));util.removeElements(t),super.removeUnwantedElementsFromContentElement(e)}findChapterTitle(e){let t=e.querySelector("div.c_title");return null===t?null:t.textContent.trim()}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.xsfm")}async fetchChapter(e){return this.walkPagesOfChapter(e,this.moreChapterTextUrl)}moreChapterTextUrl(e,t,r){let l=t.replace(".html","-"+r+".html"),n=l.split("/").pop();return 0<[...e.querySelectorAll("script")].filter(e=>e.textContent.includes(n)).length?l:null}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.jianjie")]}}